import{_ as t,c as a,o,a1 as d}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Google Cloud設定: 複数アカウント管理 | opencode-mystatus","description":"Google Cloud Antigravityの複数アカウント設定・管理方法を学びます。4つのモデルのマッピング関係とクォータクエリ方法を理解できます。","frontmatter":{"title":"Google Cloud設定: 複数アカウント管理 | opencode-mystatus","sidebarTitle":"Google Cloud","subtitle":"Google Cloud高度な設定：複数アカウントとモデル管理","description":"Google Cloud Antigravityの複数アカウント設定・管理方法を学びます。4つのモデルのマッピング関係とクォータクエリ方法を理解できます。","tags":["Google Cloud","複数アカウント管理","Antigravity","モデルマッピング"],"prerequisite":["start-quick-start"],"order":1},"headers":[],"relativePath":"ja/vbgate/opencode-mystatus/advanced/google-setup/index.md","filePath":"ja/vbgate/opencode-mystatus/advanced/google-setup/index.md"}'),l={name:"ja/vbgate/opencode-mystatus/advanced/google-setup/index.md"};function r(i,e,n,s,h,c){return o(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="google-cloud高度な設定-複数アカウントとモデル管理" tabindex="-1">Google Cloud高度な設定：複数アカウントとモデル管理 <a class="header-anchor" href="#google-cloud高度な設定-複数アカウントとモデル管理" aria-label="Permalink to &quot;Google Cloud高度な設定：複数アカウントとモデル管理&quot;">​</a></h1><h2 id="学習後のスキル" tabindex="-1">学習後のスキル <a class="header-anchor" href="#学習後のスキル" aria-label="Permalink to &quot;学習後のスキル&quot;">​</a></h2><p>複数のGoogle Cloud Antigravityアカウントを設定し、すべてのアカウントのクォータ使用状況を一括確認し、4つのモデルのマッピング関係（G3 Pro、G3 Image、G3 Flash、Claude）を理解します。</p><h2 id="コア概念" tabindex="-1">コア概念 <a class="header-anchor" href="#コア概念" aria-label="Permalink to &quot;コア概念&quot;">​</a></h2><h3 id="複数アカウントサポート" tabindex="-1">複数アカウントサポート <a class="header-anchor" href="#複数アカウントサポート" aria-label="Permalink to &quot;複数アカウントサポート&quot;">​</a></h3><p>opencode-mystatusは同時に複数のGoogle Cloud Antigravityアカウントをクエリできます。各アカウントは独立して4つのモデルのクォータを表示し、複数プロジェクトのクォータ割り当てを管理するのに便利です。</p><h3 id="モデルマッピング関係" tabindex="-1">モデルマッピング関係 <a class="header-anchor" href="#モデルマッピング関係" aria-label="Permalink to &quot;モデルマッピング関係&quot;">​</a></h3><table tabindex="0"><thead><tr><th>表示名</th><th>モデルKey（メイン）</th><th>モデルKey（サブ）</th></tr></thead><tbody><tr><td>G3 Pro</td><td><code>gemini-3-pro-high</code></td><td><code>gemini-3-pro-low</code></td></tr><tr><td>G3 Image</td><td><code>gemini-3-pro-image</code></td><td>-</td></tr><tr><td>G3 Flash</td><td><code>gemini-3-flash</code></td><td>-</td></tr><tr><td>Claude</td><td><code>claude-opus-4-5-thinking</code></td><td><code>claude-opus-4-5</code></td></tr></tbody></table><h2 id="実践" tabindex="-1">実践 <a class="header-anchor" href="#実践" aria-label="Permalink to &quot;実践&quot;">​</a></h2><h3 id="ステップ1-最初のgoogle-cloudアカウントを追加" tabindex="-1">ステップ1：最初のGoogle Cloudアカウントを追加 <a class="header-anchor" href="#ステップ1-最初のgoogle-cloudアカウントを追加" aria-label="Permalink to &quot;ステップ1：最初のGoogle Cloudアカウントを追加&quot;">​</a></h3><p><code>opencode-antigravity-auth</code> プラグインを使用してアカウントを追加します。</p><h3 id="ステップ2-google-cloudクォータをクエリ" tabindex="-1">ステップ2：Google Cloudクォータをクエリ <a class="header-anchor" href="#ステップ2-google-cloudクォータをクエリ" aria-label="Permalink to &quot;ステップ2：Google Cloudクォータをクエリ&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/mystatus</span></span></code></pre></div><h3 id="ステップ3-2つ目のgoogle-cloudアカウントを追加" tabindex="-1">ステップ3：2つ目のGoogle Cloudアカウントを追加 <a class="header-anchor" href="#ステップ3-2つ目のgoogle-cloudアカウントを追加" aria-label="Permalink to &quot;ステップ3：2つ目のGoogle Cloudアカウントを追加&quot;">​</a></h3><p>同様の手順で別のGoogleアカウントでログインします。</p><h2 id="よくある落とし穴" tabindex="-1">よくある落とし穴 <a class="header-anchor" href="#よくある落とし穴" aria-label="Permalink to &quot;よくある落とし穴&quot;">​</a></h2><h3 id="アカウントが表示されない" tabindex="-1">アカウントが表示されない <a class="header-anchor" href="#アカウントが表示されない" aria-label="Permalink to &quot;アカウントが表示されない&quot;">​</a></h3><p><strong>原因</strong>：アカウントにemailフィールドがない。</p><p><strong>解決方法</strong>：<code>antigravity-accounts.json</code> で各アカウントに <code>email</code> フィールドがあることを確認。</p><h3 id="project-idがない" tabindex="-1">Project IDがない <a class="header-anchor" href="#project-idがない" aria-label="Permalink to &quot;Project IDがない&quot;">​</a></h3><p><strong>原因</strong>：アカウント設定に <code>projectId</code> も <code>managedProjectId</code> もない。</p><p><strong>解決方法</strong>：アカウント追加時にProject IDを設定する。</p><h2 id="まとめ" tabindex="-1">まとめ <a class="header-anchor" href="#まとめ" aria-label="Permalink to &quot;まとめ&quot;">​</a></h2><ul><li><code>opencode-antigravity-auth</code> プラグインのインストールはGoogle Cloudクォータクエリの前提</li><li>複数アカウントの同時クエリをサポートし、各アカウントは4つのモデルのクォータを表示</li><li>モデルマッピング：G3 Pro（high/lowサポート）、G3 Image、G3 Flash、Claude（thinking/normal）</li></ul><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を展開</strong></summary><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>モデル設定マッピング</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>69-78</td></tr><tr><td>複数アカウント並列クエリ</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>327-334</td></tr></tbody></table></details>',27)])])}const p=t(l,[["render",r]]);export{u as __pageData,p as default};
